Below is an idea, where the `pvsystem.single_diode` function is essentially the same as the current `pvsystem.singlediode`. Note the overloading of `F` and `H` vs. `effective_irradiance` and `cell_temp`, respectively, in the highest level method `calc_model_dc` of `PVSystem`, because if one is using a matched reference cell with a back-of-cell temperature sensor, then `F` and `H` are directly available, otherwise `F` and `H` would typically be first derived from SAPM's `effective irradiance` and `cell_temp`, like the other single diode models. This removes a lot of wrappers in `PVSystem`, but I haven't totally thought through the SAPM and PVWatts integration at this level or "all the things" into the higher level `ModelChain`.

```python
class PVSystem(object):
...
    # This property would normally be set by PVSystem constructor
    self.model_dc = 'pvsyst_v6'  # or 'desoto' or 'campanelli' or 'sapm' or 'pvwatts'

    def calc_model_dc(self, overloaded_irradiance, overloaded_temperature):
        if self.model_dc ==  'pvsyst_v6':
            return single_diode(get_params_pvsyst_v6(overloaded_irradiance, overloaded_temperature, **self.module_parameters))
        elif self.model_dc ==  'desoto':
            return single_diode(get_params_desoto(overloaded_irradiance, overloaded_temperature, **self.module_parameters)
        elif self.model_dc ==  'campanelli':
            return single_diode(get_params_single_diode_campanelli(overloaded_irradiance, overloaded_temperature, **self.module_parameters)
        elif self.model_dc ==  'sapm':
            return sapm(overloaded_irradiance, overloaded_temperature, **self.module_parameters)
        elif self.model_dc ==  'pvwatts':
            return pvwatts_dc(overloaded_irradiance, overloaded_temperature, **self.pvwatts_parameters)

# These are module-level functions in pvsystem, without wrappers.
def single_diode(...):
    # Essentially the same as current singlediode function (not sure about system scaling here)
    ...
    return ...

def get_params_pvsyst_v6(effective_irradiance, cell_temp, **kwargs):
    ...
    return IL, I0, Rs, Rsh, NsVth

def get_params_desoto(effective_irradiance, cell_temp, **kwargs):
    ...
    return IL, I0, Rs, Rsh, NsVth

def get_params_campanelli(F, H, **kwargs):
    ...
    return IL, I0, Rs, Rsh, NsVth

def sapm(self, effective_irradiance, temp_cell, **kwargs)
    ...
    return ...

def pvwatts_dc(g_poa_effective, temp_cell, **kwargs)
    ...
    return ...

```

Applications is pretty basic, built to benchmark performance with our model.
```
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <time.h>
#include <c_api_runtime.h>

int main(int argc, char **argv) {
    PredictorHandle predictor;
    if (TreelitePredictorLoad("model/predictor.so", 0, 1, predictor) == -1) {
        printf("Predictor load failed");
        return -1;
    }

    int lines = 1000;
    int features = 374;

    //Open and load raw data from file
    FILE *fstream = fopen("input_data_no_header.csv","r");
    if (fstream == NULL)
    {
        printf("\n file opening failed ");
        return -1 ;
    }

    float *data = (float *)malloc(lines * features * sizeof(float));
    char *line = NULL;
    char *pt;
    size_t len = 0;
    ssize_t read;
    int x = 0;
    int y = 0;

    while ((read = getline(&line, &len, fstream)) != -1 && x < lines) {
        y = 0;
        pt = strtok(line, ",");
        while (pt != NULL) {
            data[x * features + y] = (float)atof(pt);
            pt = strtok (NULL, ",");
            y++;
        }
        x++;
    }

    printf("File read.\n\n");

    DenseBatchHandle batch;
    if (TreeliteAssembleDenseBatch(data, 0, (size_t)lines, (size_t)features, batch) == -1) {
        printf("Creating batch failed");
        return -1;
    }

    float* predicitons = (float*)malloc(lines * sizeof(float));
    float size;
    int reps = 100;

    clock_t start = clock();
    for (int i=0;i<reps;i++) {
        if (TreelitePredictorPredictBatch(predictor, batch, 0, 1, 1, predicitons, (size_t*)&size) == -1) {
            printf("Prediction failed");
            return -1;
        }
    }
    clock_t end = clock();
    float diff = ((float)(end - start) / 1000000.0F ) * 1000;   
    printf("Duration %f\n", diff/reps);
}
```
